SELECT description
FROM data_storage_systems
WHERE type = 'message broker' AND last_updated = '2023-10-01';

SELECT DISTINCT dss.name
FROM data_storage_systems dss
INNER JOIN user_interactions ui ON dss.system_id = ui.system_id;

SELECT capability_name
FROM capabilities
WHERE supported = 1;

SELECT name 
FROM data_storage_systems
ORDER BY name ASC;

SELECT MAX(interaction_date)
FROM user_interactions
WHERE user_id = (SELECT user_id FROM users WHERE username = 'john_doe');

SELECT system_id, ttl_value, ttl_description
FROM ttl
WHERE ttl_status = 'active';

SELECT username
FROM users
WHERE user_id IN (
  SELECT DISTINCT user_id
  FROM user_interactions
);

SELECT COUNT(*) AS interaction_count
FROM user_interactions
WHERE user_id = (SELECT user_id FROM users WHERE username = 'john_doe');
